#include<bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
const int N=110;
int n,k,m,s,t,g[N][N],dis[N][N],c[N],ex[N][N],ans,cnt,pa[N];
void dfs(int u,int d)//dfs
{
    if(d+dis[s][u]>=ans)return;
    if(u==s)ans=d;
    else
    {
        for(int i=1;i<=n;i++)
            if(g[i][u]<inf)
            {
                int fl=1;
                for(int j=0;j<cnt;j++)
                    if(ex[pa[j]][c[i]])
                    {
                        fl=0;
                        break;
                    }
                if(!fl)continue;
                pa[cnt++]=c[i];
                dfs(i,d+g[i][u]);
                cnt--;
            }
    }
}
signed main()
{
    memset(g,0x3f,sizeof g);
    n=read(),k=read(),m=read(),s=read(),t=read();
    FOR(i,1,n)c[i]=read(),g[i][i]=0;
    FOR(i,1,k)FOR(j,1,k)ex[i][j]=read();
    FOR(i,1,k)ex[i][i]=1;
    wh(m--)
    {
        int a=read(),b=read(),w=read();
        g[a][b]=g[b][a]=min(g[a][b],w);
    }
    memcpy(dis,g,sizeof dis);
    FOR(kk,1,n)FOR(i,1,n)FOR(j,1,n)dis[i][j]=min(dis[i][kk]+dis[kk][j],dis[i][j]);//floyd
    pa[cnt++]=c[t];
    ans=inf;
    dfs(t,0);
    if(ans==inf)ans=-1;
    writeln(ans);
    return 0;
}
